  1→import { createContext, useContext, useEffect, useReducer } from 'react';
  2→import { TOOLS } from '@/editor/tools';
  3→import { DEFAULT_ZOOM } from '@/domain/defaults';
  4→
  5→const EditorContext = createContext(null);
  6→
  7→function normalizeViewMode(viewMode) {
  8→  if (viewMode === 'elevation_side') return 'elevation_left';
  9→  return viewMode;
 10→}
 11→
 12→function getInitialModelViewport() {
 13→  return { panX: 400, panY: 300, zoom: DEFAULT_ZOOM };
 14→}
 15→
 16→function getInitialSheetViewport() {
 17→  return { panX: 120, panY: 80, zoom: 2 };
 18→}
 19→
 20→function editorReducer(state, action) {
 21→  switch (action.type) {
 22→    case 'SET_TOOL':
 23→      return {
 24→        ...state,
 25→        activeTool: action.tool,
 26→        toolState: {},
 27→        selectedId: null,
 28→        selectedType: null,
 29→        statusMessage: null,
 30→      };
 31→
 32→    case 'SET_VIEW_MODE':
 33→      return {
 34→        ...state,
 35→        workspaceMode: 'model',
 36→        viewMode: normalizeViewMode(action.viewMode),
 37→        viewport: { ...state.modelViewport },
 38→        toolState: {},
 39→        selectedId: null,
 40→        selectedType: null,
 41→        statusMessage: null,
 42→      };
 43→
 44→    case 'SET_WORKSPACE_MODE':
 45→      return {
 46→        ...state,
 47→        workspaceMode: action.workspaceMode,
 48→        viewport: action.workspaceMode === 'sheet'
 49→          ? { ...state.sheetViewport }
 50→          : { ...state.modelViewport },
 51→        toolState: {},
 52→        selectedId: null,
 53→        selectedType: null,
 54→        statusMessage: null,
 55→      };
 56→
 57→    case 'SET_ACTIVE_SHEET':
 58→      return {
 59→        ...state,
 60→        activeSheetId: action.sheetId,
 61→        selectedId: null,
 62→        selectedType: null,
 63→        statusMessage: null,
 64→      };
 65→
 66→    case 'SELECT_OBJECT':
 67→      return {
 68→        ...state,
 69→        selectedId: action.id,
 70→        selectedType: action.objectType,
 71→      };
 72→
 73→    case 'DESELECT':
 74→      return {
 75→        ...state,
 76→        selectedId: null,
 77→        selectedType: null,
 78→      };
 79→
 80→    case 'UPDATE_TOOL_STATE':
 81→      return {
 82→        ...state,
 83→        toolState: { ...state.toolState, ...action.payload },
 84→      };
 85→
 86→    case 'SET_VIEWPORT':
 87→      return {
 88→        ...state,
 89→        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
 90→        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
 91→        viewport: { ...action.viewport },
 92→      };
 93→
 94→    case 'PAN':
 95→      return {
 96→        ...state,
 97→        modelViewport: state.workspaceMode === 'model'
 98→          ? {
 99→              ...state.modelViewport,
100→              panX: state.modelViewport.panX + action.dx,
101→              panY: state.modelViewport.panY + action.dy,
102→            }
103→          : state.modelViewport,
104→        sheetViewport: state.workspaceMode === 'sheet'
105→          ? {
106→              ...state.sheetViewport,
107→              panX: state.sheetViewport.panX + action.dx,
108→              panY: state.sheetViewport.panY + action.dy,
109→            }
110→          : state.sheetViewport,
111→        viewport: {
112→          ...state.viewport,
113→          panX: state.viewport.panX + action.dx,
114→          panY: state.viewport.panY + action.dy,
115→        },
116→      };
117→
118→    case 'ZOOM': {
119→      const { zoom, panX, panY } = action;
120→      return {
121→        ...state,
122→        modelViewport: state.workspaceMode === 'model' ? { zoom, panX, panY } : state.modelViewport,
123→        sheetViewport: state.workspaceMode === 'sheet' ? { zoom, panX, panY } : state.sheetViewport,
124→        viewport: { zoom, panX, panY },
125→      };
126→    }
127→
128→    case 'TOGGLE_GRID':
129→      return { ...state, showGrid: !state.showGrid };
130→
131→    case 'TOGGLE_SNAP':
132→      return { ...state, snapEnabled: !state.snapEnabled };
133→
134→    case 'SET_ACTIVE_FLOOR':
135→      return { ...state, activeFloorId: action.floorId, statusMessage: null };
136→
137→    case 'SET_STATUS_MESSAGE':
138→      return { ...state, statusMessage: action.message };
139→
140→    case 'CLEAR_STATUS_MESSAGE':
141→      if (!state.statusMessage) return state;
142→      return { ...state, statusMessage: null };
143→
144→    default:
145→      return state;
146→  }
147→}
