149→export function createInitialEditorState(activeFloorId) {
150→  const modelViewport = getInitialModelViewport();
151→  const sheetViewport = getInitialSheetViewport();
152→  return {
153→    activeTool: TOOLS.SELECT,
154→    selectedId: null,
155→    selectedType: null,
156→    toolState: {},
157→    workspaceMode: 'model',
158→    viewport: { ...modelViewport },
159→    modelViewport,
160→    sheetViewport,
161→    showGrid: true,
162→    snapEnabled: true,
163→    viewMode: 'plan',
164→    activeFloorId,
165→    activeSheetId: null,
166→    statusMessage: null,
167→  };
