41→export function projectPlanPoints(view, points = []) {
42→  if (!points.length) return null;
43→
44→  const horizontals = points.map((point) => projectElevationHorizontal(view, point));
45→  const depths = points.map((point) => projectElevationDepth(view, point));
46→
47→  return {
48→    left: Math.min(...horizontals),
49→    right: Math.max(...horizontals),
50→    depth: depths.reduce((sum, value) => sum + value, 0) / depths.length,
51→  };
