 1→import { GRID_MINOR, MIN_WALL_LENGTH } from '@/domain/defaults';
 2→import { createSectionCut } from '@/domain/models';
 3→import { distance } from '@/geometry/point';
 4→
 5→function snapToGrid(value) {
 6→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 7→}
 8→
 9→function resolvePoint(modelPos, snapEnabled) {
10→  if (!snapEnabled) return { x: modelPos.x, y: modelPos.y };
11→  return {
12→    x: snapToGrid(modelPos.x),
13→    y: snapToGrid(modelPos.y),
14→  };
15→}
16→
17→function resetSectionTool(editorDispatch) {
18→  editorDispatch({
19→    type: 'UPDATE_TOOL_STATE',
20→    payload: {
21→      sectionStartPoint: null,
22→      sectionPreviewPoint: null,
23→    },
24→  });
25→}
26→
27→export function createSectionPlaceHandler({ dispatch, editorDispatch, activeFloorId, getFloor, snapEnabled }) {
28→  return {
29→    onMouseDown(modelPos, e, toolState) {
30→      if (e.button !== 0) return;
31→
32→      const point = resolvePoint(modelPos, snapEnabled);
33→      if (!toolState.sectionStartPoint) {
34→        editorDispatch({
35→          type: 'UPDATE_TOOL_STATE',
36→          payload: {
37→            sectionStartPoint: point,
38→            sectionPreviewPoint: point,
39→          },
40→        });
41→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click the end point for the section cut.' });
42→        return;
43→      }
44→
45→      if (distance(toolState.sectionStartPoint, point) < MIN_WALL_LENGTH) {
46→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Section cut is too short.' });
47→        return;
48→      }
49→
50→      const floor = getFloor(activeFloorId);
51→      const existing = floor?.sectionCut || null;
52→      const sectionCut = existing
53→        ? {
54→            ...existing,
55→            startPoint: toolState.sectionStartPoint,
56→            endPoint: point,
57→          }
58→        : createSectionCut(toolState.sectionStartPoint, point);
59→
60→      dispatch({ type: 'SECTION_SET', floorId: activeFloorId, sectionCut });
61→      editorDispatch({ type: 'SELECT_OBJECT', id: sectionCut.id, objectType: 'sectionCut' });
62→      resetSectionTool(editorDispatch);
63→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Section cut updated.' });
64→    },
65→
66→    onMouseMove(modelPos) {
67→      const point = resolvePoint(modelPos, snapEnabled);
68→      editorDispatch({
69→        type: 'UPDATE_TOOL_STATE',
70→        payload: {
71→          sectionPreviewPoint: point,
72→        },
73→      });
74→    },
75→
76→    onKeyDown(e) {
77→      if (e.key !== 'Escape') return;
78→      resetSectionTool(editorDispatch);
79→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
80→    },
81→
82→    getCursor() {
83→      return 'crosshair';
84→    },
85→  };
86→}
