  1→import { getBeamRenderData } from '@/geometry/beamGeometry';
  2→import { columnOutline } from '@/geometry/columnGeometry';
  3→import { segmentIntersection } from '@/geometry/line';
  4→import { pointInPolygon } from '@/geometry/polygon';
  5→import { projectPointToSectionCut, sectionCutLength } from '@/geometry/sectionCutGeometry';
  6→import { getStairRenderData, stairTotalRise } from '@/geometry/stairGeometry';
  7→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
  8→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  9→import { getSlabBottomLevel, getSlabTopLevel } from '@/elevations/slab';
 10→
 11→const EPSILON = 1e-6;
 12→
 13→function clamp(value, min, max) {
 14→  return Math.max(min, Math.min(max, value));
 15→}
 16→
 17→function uniqueSortedValues(values = []) {
 18→  const sorted = [...values].sort((a, b) => a - b);
 19→  return sorted.filter((value, index) => (
 20→    index === 0 || Math.abs(value - sorted[index - 1]) > 1e-4
 21→  ));
 22→}
 23→
 24→function intervalFromValues(values, maxLength) {
 25→  if (!values.length) return null;
 26→  const clamped = values
 27→    .map((value) => clamp(value, 0, maxLength))
 28→    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
 29→  if (!clamped.length) return null;
 30→
 31→  const left = Math.min(...clamped);
 32→  const right = Math.max(...clamped);
 33→  if (right - left < EPSILON) return null;
 34→  return { left, right };
 35→}
 36→
 37→function projectPolygon(sectionCut, polygon = []) {
 38→  return polygon.map((point) => projectPointToSectionCut(sectionCut, point));
 39→}
 40→
 41→function polygonCutInterval(sectionCut, polygon = []) {
 42→  if (polygon.length < 3) return null;
 43→
 44→  const values = [];
 45→  for (let index = 0; index < polygon.length; index += 1) {
 46→    const start = polygon[index];
 47→    const end = polygon[(index + 1) % polygon.length];
 48→    const hit = segmentIntersection(sectionCut.startPoint, sectionCut.endPoint, start, end);
 49→    if (hit) {
 50→      values.push(projectPointToSectionCut(sectionCut, hit).along);
 51→    }
 52→  }
 53→
 54→  if (pointInPolygon(sectionCut.startPoint, polygon)) values.push(0);
 55→  if (pointInPolygon(sectionCut.endPoint, polygon)) values.push(sectionCutLength(sectionCut));
 56→
 57→  return intervalFromValues(uniqueSortedValues(values), sectionCutLength(sectionCut));
 58→}
 59→
 60→function polygonProjectionInfo(sectionCut, polygon = [], depth) {
 61→  if (polygon.length < 3) return null;
 62→  const projected = projectPolygon(sectionCut, polygon);
 63→  const alongs = projected.map((entry) => entry.along);
 64→  const offsets = projected.map((entry) => entry.offset);
 65→  const minOffset = Math.min(...offsets);
 66→  const maxOffset = Math.max(...offsets);
 67→
 68→  if (maxOffset < -EPSILON || minOffset > depth + EPSILON) return null;
 69→
 70→  return {
 71→    interval: intervalFromValues(alongs, sectionCutLength(sectionCut)),
 72→    depth: offsets.reduce((sum, value) => sum + Math.max(0, value), 0) / Math.max(1, offsets.length),
 73→    minOffset,
 74→    maxOffset,
 75→  };
 76→}
 77→
 78→function createSceneRect(id, category, renderMode, interval, bottom, top, depth, sourceId) {
 79→  if (!interval) return null;
 80→  if (interval.right - interval.left < EPSILON) return null;
 81→  if (Math.abs(top - bottom) < EPSILON) return null;
 82→
 83→  return {
 84→    id,
 85→    category,
 86→    renderMode,
 87→    left: interval.left,
 88→    right: interval.right,
 89→    bottom,
 90→    top,
 91→    depth,
 92→    sourceId,
 93→  };
 94→}
 95→
 96→function createFootprintRect(id, category, sourceId, sectionCut, polygon, bottom, top, depthLimit) {
 97→  const cutInterval = polygonCutInterval(sectionCut, polygon);
 98→  if (cutInterval) {
 99→    return createSceneRect(id, category, 'cut', cutInterval, bottom, top, 0, sourceId);
100→  }
101→
102→  const projection = polygonProjectionInfo(sectionCut, polygon, depthLimit);
103→  if (!projection?.interval) return null;
104→  return createSceneRect(id, category, 'projection', projection.interval, bottom, top, projection.depth, sourceId);
105→}
106→
107→function buildWallElements(floor, sectionCut) {
108→  return (floor.walls || [])
109→    .map((wall) => {
110→      const outline = getWallRenderData(wall, floor.columns || []).outline;
111→      return createFootprintRect(
112→        `section-wall-${wall.id}`,
113→        'wall',
114→        wall.id,
115→        sectionCut,
116→        outline,
117→        floor.level ?? 0,
118→        (floor.level ?? 0) + (wall.height ?? 0),
119→        sectionCut.depth
120→      );
121→    })
122→    .filter(Boolean);
123→}
124→
125→function buildSlabElements(floor, sectionCut) {
126→  if (!floor.slab?.boundaryPoints?.length) return [];
127→  return [
128→    createFootprintRect(
129→      `section-slab-${floor.slab.id}`,
130→      'slab',
131→      floor.slab.id,
132→      sectionCut,
133→      floor.slab.boundaryPoints,
134→      getSlabBottomLevel(floor.slab),
135→      getSlabTopLevel(floor.slab),
136→      sectionCut.depth
137→    ),
138→  ].filter(Boolean);
139→}
140→
141→function buildColumnElements(floor, sectionCut) {
142→  return (floor.columns || [])
143→    .map((column) => createFootprintRect(
144→      `section-column-${column.id}`,
145→      'column',
146→      column.id,
147→      sectionCut,
148→      columnOutline(column),
149→      floor.level ?? 0,
150→      (floor.level ?? 0) + column.height,
151→      sectionCut.depth
152→    ))
153→    .filter(Boolean);
154→}
155→
156→function buildBeamElements(floor, sectionCut) {
157→  return (floor.beams || [])
158→    .map((beam) => {
159→      const renderData = getBeamRenderData(beam, floor.columns || []);
160→      if (!renderData) return null;
161→      return createFootprintRect(
162→        `section-beam-${beam.id}`,
163→        'beam',
164→        beam.id,
165→        sectionCut,
166→        renderData.outline,
167→        beam.floorLevel - beam.depth,
168→        beam.floorLevel,
169→        sectionCut.depth
170→      );
171→    })
172→    .filter(Boolean);
173→}
174→
175→function buildDoorElements(floor, sectionCut) {
176→  return (floor.doors || [])
177→    .map((door) => {
178→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
179→      if (!wall) return null;
180→      const info = doorOutlineOnWall(wall, door);
181→      return createFootprintRect(
182→        `section-door-${door.id}`,
183→        'door',
184→        door.id,
185→        sectionCut,
186→        [info.p1, info.p2, info.p3, info.p4],
187→        (floor.level ?? 0) + (door.sillHeight ?? 0),
188→        (floor.level ?? 0) + (door.sillHeight ?? 0) + (door.height ?? 0),
189→        sectionCut.depth
190→      );
191→    })
192→    .filter(Boolean);
193→}
194→
195→function buildWindowElements(floor, sectionCut) {
196→  return (floor.windows || [])
197→    .map((windowItem) => {
198→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
199→      if (!wall) return null;
200→      const info = windowOutlineOnWall(wall, windowItem);
201→      return createFootprintRect(
202→        `section-window-${windowItem.id}`,
203→        'window',
204→        windowItem.id,
205→        sectionCut,
206→        [info.p1, info.p2, info.p3, info.p4],
207→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0),
208→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
209→        sectionCut.depth
210→      );
211→    })
212→    .filter(Boolean);
213→}
214→
215→function buildStairElements(floor, sectionCut) {
216→  return (floor.stairs || [])
217→    .map((stair) => {
218→      const renderData = getStairRenderData(stair);
219→      if (!renderData) return null;
220→
221→      const cutInterval = polygonCutInterval(sectionCut, renderData.outline);
222→      const projection = polygonProjectionInfo(sectionCut, renderData.outline, sectionCut.depth);
223→      const interval = cutInterval || projection?.interval;
224→      if (!interval) return null;
225→
226→      const startProjection = projectPointToSectionCut(sectionCut, renderData.startPoint);
227→      const endProjection = projectPointToSectionCut(sectionCut, renderData.endPoint);
228→      const clampedStart = clamp(startProjection.along, 0, sectionCutLength(sectionCut));
229→      const clampedEnd = clamp(endProjection.along, 0, sectionCutLength(sectionCut));
230→      if (Math.abs(clampedEnd - clampedStart) < EPSILON) return null;
231→
232→      const risers = Math.max(1, stair.numberOfRisers || 1);
233→      const rise = stairTotalRise(stair);
234→      const risePerRiser = rise / risers;
235→      const alongStep = (clampedEnd - clampedStart) / risers;
236→      const points = [{ x: clampedStart, z: floor.level ?? 0 }];
237→      let currentAlong = clampedStart;
238→      let currentZ = floor.level ?? 0;
239→
240→      for (let index = 0; index < risers; index += 1) {
241→        currentAlong += alongStep;
242→        points.push({ x: currentAlong, z: currentZ });
243→        currentZ += risePerRiser;
244→        points.push({ x: currentAlong, z: currentZ });
245→      }
246→
247→      return {
248→        id: `section-stair-${stair.id}`,
249→        category: 'stair',
250→        renderMode: cutInterval ? 'cut' : 'projection',
251→        points,
252→        depth: projection?.depth ?? 0,
253→        sourceId: stair.id,
254→      };
255→    })
256→    .filter(Boolean);
257→}
258→
259→function computeSceneBounds(rects, stairs, sectionCut, baseLevel) {
260→  const stairXs = stairs.flatMap((element) => element.points.map((point) => point.x));
261→  const stairZs = stairs.flatMap((element) => element.points.map((point) => point.z));
262→  const rectXs = rects.flatMap((element) => [element.left, element.right]);
263→  const rectZs = rects.flatMap((element) => [element.bottom, element.top]);
264→  const xs = [...rectXs, ...stairXs];
265→  const zs = [...rectZs, ...stairZs];
266→
267→  if (!xs.length || !zs.length) {
268→    return {
269→      minX: 0,
270→      maxX: sectionCutLength(sectionCut) || 3000,
271→      minZ: baseLevel,
272→      maxZ: baseLevel + 3000,
273→    };
274→  }
275→
276→  return {
277→    minX: Math.min(...xs),
278→    maxX: Math.max(...xs),
279→    minZ: Math.min(baseLevel, ...zs),
280→    maxZ: Math.max(...zs),
281→  };
282→}
283→
284→export function buildSectionScene(floor) {
285→  if (!floor?.sectionCut) return null;
286→
287→  const rectElements = [
288→    ...buildWallElements(floor, floor.sectionCut),
289→    ...buildSlabElements(floor, floor.sectionCut),
290→    ...buildColumnElements(floor, floor.sectionCut),
291→    ...buildBeamElements(floor, floor.sectionCut),
292→    ...buildDoorElements(floor, floor.sectionCut),
293→    ...buildWindowElements(floor, floor.sectionCut),
294→  ].sort((a, b) => {
295→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
296→    return a.depth - b.depth;
297→  });
298→
299→  const stairElements = buildStairElements(floor, floor.sectionCut).sort((a, b) => {
300→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
301→    return a.depth - b.depth;
302→  });
303→
304→  return {
305→    viewKey: 'section_view',
306→    title: floor.sectionCut.label || 'Section',
307→    rectElements,
308→    stairElements,
309→    bounds: computeSceneBounds(rectElements, stairElements, floor.sectionCut, floor.level ?? 0),
310→    groundLevel: floor.level ?? 0,
311→  };
312→}
313→

